CREATE OR REPLACE FUNCTION fpb_gos_loan_collnum (as_conno char,ai_num integer) RETURNS char AS $body$
DECLARE

  cur_data CURSOR FOR
  SELECT COLLATERAL_NO
  from sc_lon_m_contract_coll
  where loan_contract_no = as_conno
  and status = '0'
  and collateral_type_code = '01'
  order by COLLATERAL_NO;
  type tab_data is table of cur_data%rowtype index by integer;ltab_data tab_data;
  li_count integer;

BEGIN
  /*ต้องการ COLLATERAL_NO ของลำดับคนที่ค้ำเพื่อออกรายงานคนค้ำ เป็นคอลัมล์ ๆ*/

  open cur_data;fetch cur_data bulk collect into ltab_data;close cur_data;
  li_count := ltab_data.count;
  if ai_num > li_count  then
    return null;
  else
    if ai_num > 0 then
      return ltab_data[ai_num].COLLATERAL_NO;
    else
      return null;
    end if;
  end if;
exception when others then CALL spa_dberror('fpb_gos_loan_collnum');
end;
$body$
LANGUAGE PLPGSQL
SECURITY DEFINER
;
